recognition.onend = () => {
        console.log("음성 인식이 중단되었습니다.");
        isListening = false;

        // [수정] 사용자가 직접 끈 경우, isRestarting 플래그를 확실히 false로 만들어줍니다.
        if (userManuallyStopped) {
            isRestarting = false; 
        } else {
            // 자동 재시작 로직
            isRestarting = true; 
            console.log("STT 세션이 만료되어 재시작합니다.");
            try {
                setTimeout(() => {
                    // 이 시점에 사용자가 끄기 버튼을 눌렀을 수 있으므로 한번 더 체크
                    if (userManuallyStopped) {
                        isRestarting = false;
                        updateVoiceButtonUI();
                        return;
                    }
                    recognition.start();
                    isRestarting = false;
                }, 250);
            } catch (e) {
                console.error("STT 재시작 실패:", e);
                isRestarting = false;
            }
        }
        updateVoiceButtonUI();
    };

