function toggleVoiceCommand() {
    if (!recognition) return;
    if (isRestarting) {
        console.warn("STT가 재시작 중입니다. 잠시 후 다시 시도해주세요.");
        return;
    }

    // [수정] isListening과 userManuallyStopped의 상태를 동시에 확인하여 명령을 결정
    const isActuallyListening = isListening && !userManuallyStopped;

    if (isActuallyListening) {
        // 켜져 있는 상태에서 끄려고 할 때
        userManuallyStopped = true;
        recognition.stop();
    } else {
        // 꺼져 있는 상태에서 켜려고 할 때 (또는 onend 직후 재시작을 기다리는 상태일 때)
        // recognition.stop()이 호출되면 onend 이벤트에서 userManuallyStopped를 다시 false로 처리해주므로
        // 여기서는 플래그만 설정하고 start()를 호출합니다.
        userManuallyStopped = false;
        try {
            recognition.start();
        } catch(e) {
            // 이미 켜져 있는데 켜려고 시도해서 나는 오류는 여기서 잡힙니다.
            console.error("음성 인식을 시작할 수 없습니다:", e);
            // 혹시 모를 상태 꼬임 방지를 위해 UI를 한번 더 업데이트합니다.
            updateVoiceButtonUI();
        }
    }
    // [제거] 불필요한 UI 업데이트 호출을 제거합니다.
    // onstart, onend 이벤트 핸들러가 정확한 시점에 UI를 업데이트하므로 이 호출은 상태 꼬임의 원인이 됩니다.
    // updateVoiceButtonUI(); 
}

patches.new_code:
function toggleVoiceCommand() {
    if (!recognition) return;

    if (userManuallyStopped) {
        // 꺼져있는 상태 -> 켭니다.
        userManuallyStopped = false;
        try {
            recognition.start();
        } catch(e) {
            // 엣지에서 가끔 발생하는 찌꺼기 상태 강제 정리
            console.log("강제 초기화 후 다시 시작");
            recognition.abort(); // stop보다 강력한 강제 종료
            setTimeout(() => { 
                if(!userManuallyStopped) recognition.start(); 
            }, 100);
        }
    } else {
        // 켜져있는 상태 -> 끕니다.
        userManuallyStopped = true;
        recognition.stop();
    }
    updateVoiceButtonUI();
}
